function createOrUpdateEntityList(entityListResource, listConfig) {
  return entityListResource.getEntityList({ entityListFullName: listConfig.name + '@' + listConfig.nameSpace, responseFields: 'entityUsages' })
    .then(function(existingList) {
      if (!existingList.usages || existingList.usages.length === 0) {
        // Delete the existing entity list
        return entityListResource.deleteEntityList({ entityListFullName: listConfig.name + '@' + listConfig.nameSpace })
          .then(function() {
            console.log('Deleted existing entity list: ' + listConfig.name);
            // Create the entity list
            return entityListResource.createEntityList({ responseFields: '' }, { body: listConfig });
          })
          .then(function() {
            console.log('Successfully created entity list: ' + listConfig.name);
          });
      } else {
        console.log('Entity list ' + listConfig.name + ' already exists with usages. Skipping recreation.');
        return Promise.resolve();
      }
    })
    .catch(function(e) {
      if (e.originalError.statusCode === 404) {
        // If the entity list doesn't exist, create it
        return entityListResource.createEntityList({ responseFields: '' }, { body: listConfig })
          .then(function() {
            console.log('Successfully created entity list: ' + listConfig.name);
          });
      } else {
        console.log('Error handling entity list ' + listConfig.name + ':');
        console.log(e);
        return Promise.reject(e);
      }
    });
}

