module.exports = function(context, callback) {
  var entityListResource = entityListResourceFactory({ context: context.apiContext });
  var entityResource = entityResourceFactory({ context: context.apiContext });
  var documentListResource = documentlistsResourceFactory({ context: context.apiContext });
  var customerAttributeResource = customerAttributeResourceFactory({ context: context.apiContext });
  var orderAttributeResource = orderAttributeResourceFactory({ context: context.apiContext });

  console.log('Installing or updating entity lists...');

  createOrUpdateEntityLists(entityListResource)
    .then(function() { return createVertexConfigEntity(entityResource); })
    .then(function() { return createEntityEditorEntry(documentListResource); })
    .then(function() {
    console.log("created entity list");
    }).catch(function(err) {
      console.log("did not create entity list");
    }).finally(function(err) {
      console.info(context.get.installationState());
      console.info(context.get.exports());
      var installer = new ActionInstaller({ context: context.apiContext });

      var addTimeout = function(funcDef) {
        funcDef.timeoutMilliseconds = 15000;
      };
      var configurators = {
        "http.commerce.catalog.storefront.tax.estimateTaxes.before": addTimeout,
        "embedded.commerce.orders.action.before": addTimeout,
        "embedded.commerce.return.actions.before": addTimeout
      };

      console.info(context);
      installer.enableActions(context, null, configurators)
        .then(callback.bind(null, null), callback)
        .catch(function(err) {
          console.error(err);
          callback(err);
        });
    });
};
